module RefModule(
	input clk,
	input rst_n,
	input up_down,
	output reg [3:0] counter
);

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or negedge rst_n or posedge dbg_halt) begin
		if(!rst_n)
			counter <= 4'b0000;
		else if(up_down)
			counter <= counter + 1'b1;
		else
			counter <= counter - 1'b1;
	end

endmodule
